import React, { useEffect } from "react";
import "aos/dist/aos.css";
import AOS from "aos";

const projects = [
  {
    title: "Customer Discount Request",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `A sophisticated plugin for Shopware 6 allowing B2B/B2C users to negotiate prices dynamically. Featured on the official Shopware store.`,
    link: "https://store.shopware.com/en/brand27683468217m/customer-discount-request.html",
  },
  {
    title: "Customer Membership Program",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Tiered loyalty system (Silver, Gold, Platinum) with dynamic discount logic based on lifetime purchase milestones.`,
    link: "https://store.shopware.com/en/brand53235685891m/customer-membership-program.html"
  },
  {
    title: "Ticket System",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Event management and ticketing infrastructure for Shopware. Manages inventory, pricing, and availability in real-time.`,
    link: "https://store.shopware.com/en/brand11399667561m/ticket-system.html"
  },
  {
    title: "Order Status Analytics",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Visualized order tracking and status metrics for enhanced customer transparency and higher trust levels.`,
    link: "https://store.shopware.com/en/brand86225088288m/order-status-analytics.html"
  },
  {
    title: "Archive Portal",
    platform: "Node.js",
    domain: "Internal Drive",
    type: "System",
    description: `A Google Drive-clone for internal enterprise use. Features role-based access control and secure project-specific file hosting.`,
    keyFeatures: ["Admin/Employee Roles", "Project Isolation", "Secure Hosting"]
  },
  {
    title: "Geocoding API Engine",
    platform: "Odoo 17",
    domain: "Event Booking",
    type: "Client",
    description: `Location-aware event engine powered by Google Geocoding API. Features proximity-based event discovery.`,
    keyFeatures: ["Geographic Radius Filtering", "API Load Balancing", "Real-time Discovery"]
  },
  {
    title: "Production Unit ERP",
    platform: "Laravel",
    domain: "Manufacturing",
    type: "Client",
    description: `Enterprise resource planning suite for manufacturing, handling cost estimation, production workflows, and inventory.`,
    keyFeatures: ["Cost Auditing", "Workflow Automation", "Logistics Control"]
  }
];

const Projects = () => {
  useEffect(() => {
    AOS.init({ duration: 1200, easing: "ease-out-back", once: true });
  }, []);

  return (
    <section id="projects" className="section">
      <div className="container section-title" data-aos="fade-up">
        <h2 className="text-gradient fw-900" style={{ fontSize: '3.5rem' }}>Portfolio Case Studies</h2>
        <p className="section-subtitle">Showcasing engineered solutions across e-commerce, ERP, and API-driven architectures.</p>
      </div>

      <div className="container">
        <div className="row g-4">
          {projects.map((project, index) => (
            <div key={index} className="col-lg-6 col-xl-4" data-aos="zoom-in-up" data-aos-delay={index * 150}>
              <div className="project-card glass-v2 h-100 p-5 d-flex flex-column" style={{ border: '1px solid rgba(255,255,255,0.1)' }}>
                <div className="info-badges d-flex justify-content-between align-items-center mb-4">
                  <span className="badge glass-v2 text-primary px-3 py-2" style={{ border: '1px solid rgba(59,130,246,0.3)', background: 'rgba(59,130,246,0.1)' }}>
                    {project.platform}
                  </span>
                  <span className="text-primary small fw-bold">#{project.domain}</span>
                </div>

                <h3 className="text-white mb-3 fw-bold" style={{ fontSize: '1.4rem' }}>{project.title}</h3>
                <p className="text-white flex-grow-1 small" style={{ opacity: 0.9, lineHeight: '1.7' }}>{project.description}</p>

                {project.keyFeatures && (
                  <div className="mt-4 mb-4">
                    <ul className="list-unstyled mb-0">
                      {project.keyFeatures.map((f, i) => (
                        <li key={i} className="text-muted small mb-1"><i className="bi bi-circle-fill text-primary me-2" style={{ fontSize: '6px', verticalAlign: 'middle' }}></i> {f}</li>
                      ))}
                    </ul>
                  </div>
                )}

                <div className="mt-auto pt-4">
                  {project.link ? (
                    <a href={project.link} target="_blank" rel="noopener noreferrer" className="btn btn-premium w-100 py-3 rounded-3" style={{ fontSize: '0.9rem' }}>
                      Case Study <i className="bi bi-box-arrow-up-right ms-2"></i>
                    </a>
                  ) : (
                    <div className="text-center p-2 glass-v2 rounded-3 text-muted small" style={{ borderStyle: 'dashed' }}>
                      Internal Deployment Only
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
